Index: 
===================================================================
--- 
+++ 
@@ -1288,6 +1288,172 @@
 
   .stat-box h4 {
     font-size: 30px;
   }
+
+
+
+
+
+  /* ══════════════════════════════════════════════════════════
+   VISION & MISSION  — Redesigned
+══════════════════════════════════════════════════════════ */
+.history-modern {
+  padding: 136px 0 160px;
+  background: var(--ink-3);
+  position: relative;
+  z-index: 5;
+  overflow: hidden;
+}
+
+/* Ambient orbs */
+.vm-bg-orb {
+  position: absolute;
+  width: 640px;
+  height: 640px;
+  border-radius: 50%;
+  pointer-events: none;
+  z-index: 0;
+  filter: blur(90px);
+  animation: vmOrbFloat 10s ease-in-out infinite alternate;
+}
+
+.vm-bg-orb--left {
+  top: -160px;
+  left: -180px;
+  background: radial-gradient(circle, rgba(212, 175, 55, 0.07) 0%, transparent 70%);
+}
+
+.vm-bg-orb--right {
+  bottom: -160px;
+  right: -180px;
+  background: radial-gradient(circle, rgba(212, 175, 55, 0.055) 0%, transparent 70%);
+  animation-direction: alternate-reverse;
+}
+
+@keyframes vmOrbFloat {
+  from { transform: scale(0.88) translateY(0px); opacity: 0.7; }
+  to   { transform: scale(1.08) translateY(-30px); opacity: 1; }
+}
+
+/* Subtitle */
+.vm-section-sub {
+  font-size: 1rem;
+  color: var(--text-3);
+  font-family: var(--f-serif);
+  font-style: italic;
+  letter-spacing: 1.5px;
+  margin-top: 12px;
+}
+
+/* ── Split layout ── */
+.vm-split-layout {
+  display: grid;
+  grid-template-columns: 1fr 56px 1fr;
+  gap: 0;
+  align-items: stretch;
+  position: relative;
+  z-index: 1;
+}
+
+/* ── Panel ── */
+.vm-panel {
+  position: relative;
+  overflow: hidden;
+  border-radius: var(--r-xl);
+  border: 1px solid var(--border);
+  background: var(--card-bg);
+  backdrop-filter: blur(24px);
+  transition: border-color 0.55s var(--ease), box-shadow 0.55s var(--ease);
+  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
+}
+
+.vm-panel:hover {
+  border-color: var(--border-g);
+  box-shadow: 0 36px 80px rgba(0, 0, 0, 0.65), 0 0 0 1px rgba(212, 175, 55, 0.14);
+}
+
+.vm-panel-inner {
+  padding: 64px 56px 68px;
+  position: relative;
+  z-index: 2;
+  height: 100%;
+  display: flex;
+  flex-direction: column;
+}
+
+/* Floating roman numeral watermark */
+.vm-roman {
+  position: absolute;
+  top: -14px;
+  right: 28px;
+  font-size: 148px;
+  font-weight: 900;
+  font-family: var(--f-display);
+  color: rgba(212, 175, 55, 0.035);
+  line-height: 1;
+  pointer-events: none;
+  user-select: none;
+  transition: color 0.6s var(--ease), transform 0.6s var(--ease);
+}
+
+.vm-panel:hover .vm-roman {
+  color: rgba(212, 175, 55, 0.08);
+  transform: translateY(-6px) scale(1.03);
+}
+
+/* SVG icon ring */
+.vm-icon-wrap {
+  width: 58px;
+  height: 58px;
+  margin-bottom: 28px;
+  color: var(--gold-dim);
+  transition: color 0.4s, transform 0.6s var(--ease);
+}
+
+.vm-panel:hover .vm-icon-wrap {
+  color: var(--gold);
+  transform: rotate(18deg) scale(1.08);
+}
+
+.vm-svg-icon {
+  width: 100%;
+  height: 100%;
+}
+
+/* Tag */
+.vm-panel-tag {
+  font-size: 9.5px;
+  letter-spacing: 6px;
+  text-transform: uppercase;
+  color: var(--gold);
+  font-family: var(--f-body);
+  font-weight: 600;
+  margin-bottom: 18px;
+  display: flex;
+  align-items: center;
+  gap: 10px;
+}
+
+.vm-panel-tag::after {
+  content: '';
+  display: block;
+  flex: 1;
+  max-width: 40px;
+  height: 1px;
+  background: var(--gold-dim);
+}
+
+/* Title */
+.vm-panel-title {
+  font-size: clamp(1.9rem, 2.8vw, 2.6rem);
+  font-family: var(--f-display);
+  font-weight: 700;
+  color: #fff;
+  line-height: 1.15;
+  margin-bottom: 24px;
+}
+
+/* Rule */
+.vm-panel-rule {
   
 }
\ No newline at end of file

