+/* ══════════════════════════════════════════════════════════
+   VISION & MISSION
+══════════════════════════════════════════════════════════ */
+.history-modern {
+  padding: 136px 0;
+  background: var(--ink-3);
+  position: relative;
+  z-index: 5;
+  overflow: hidden;
+}
+
+.history-modern::before {
+  content: '';
+  position: absolute;
+  inset: 0;
+  pointer-events: none;
+  background:
+    radial-gradient(ellipse 55% 60% at 12% 25%, rgba(212,175,55,0.045) 0%, transparent 60%),
+    radial-gradient(ellipse 55% 60% at 88% 75%, rgba(212,175,55,0.035) 0%, transparent 60%);
+}
+
+.history-grid {
+  display: grid;
+  grid-template-columns: 1fr 1fr;
+  gap: 32px;
+  position: relative;
+  z-index: 1;
+}
+
+/* ── Card ── */
+.vm-modern-card {
+  padding: 52px 48px 44px;
+  background: rgba(10, 10, 22, 0.85);
+  border: 1px solid rgba(255,255,255,0.06);
+  border-radius: 20px;
+  position: relative;
+  overflow: hidden;
+  backdrop-filter: blur(20px);
+  cursor: default;
+  transition: border-color 0.5s var(--ease),
+              box-shadow 0.5s var(--ease),
+              transform 0.5s var(--ease);
+  box-shadow: 0 8px 40px rgba(0,0,0,0.45);
+}
+
+.vm-modern-card:hover {
+  border-color: rgba(212,175,55,0.28);
+  box-shadow: 0 24px 64px rgba(0,0,0,0.6),
+              0 0 0 1px rgba(212,175,55,0.12);
+  transform: translateY(-10px);
+}
+
+/* Animated top gold border */
+.vm-modern-card::before {
+  content: '';
+  position: absolute;
+  top: 0; left: 0; right: 0;
+  height: 2px;
+  background: var(--gold-grad);
+  transform: scaleX(0);
+  transform-origin: left;
+  transition: transform 0.6s var(--ease);
+}
+
+.vm-modern-card:hover::before {
+  transform: scaleX(1);
+}
+
+/* ── Card top row ── */
+.vm-card-top {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  margin-bottom: 32px;
+}
+
+/* Icon circle */
+.vm-card-icon {
+  width: 52px;
+  height: 52px;
+  border-radius: 50%;
+  border: 1px solid rgba(212,175,55,0.22);
+  background: rgba(212,175,55,0.06);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  color: var(--gold);
+  transition: background 0.45s var(--ease),
+              border-color 0.45s,
+              transform 0.55s var(--ease),
+              box-shadow 0.45s;
+}
+
+.vm-modern-card:hover .vm-card-icon {
+  background: rgba(212,175,55,0.14);
+  border-color: var(--gold);
+  transform: rotate(20deg) scale(1.1);
+  box-shadow: 0 0 22px rgba(212,175,55,0.25);
+}
+
+.vm-card-icon svg {
+  width: 22px;
+  height: 22px;
+}
+
+/* Badge number */
+.vm-modern-badge {
+  font-size: 13px;
+  font-family: var(--f-body);
+  font-weight: 600;
+  letter-spacing: 3px;
+  color: rgba(212,175,55,0.35);
+  transition: color 0.4s;
+}
+
+.vm-modern-card:hover .vm-modern-badge {
+  color: var(--gold);
+}
+
+/* Title */
+.vm-modern-title {
+  font-size: 1.95rem;
+  color: #fff;
+  margin-bottom: 20px;
+  font-family: var(--f-display);
+  font-weight: 700;
+  position: relative;
+  display: inline-block;
+}
+
+.vm-modern-title::after {
+  content: '';
+  position: absolute;
+  left: 0;
+  bottom: -10px;
+  width: 28px;
+  height: 2px;
+  background: var(--gold-grad);
+  border-radius: 2px;
+  transition: width 0.5s var(--ease);
+  box-shadow: 0 0 10px rgba(212,175,55,0.4);
+}
+
+.vm-modern-card:hover .vm-modern-title::after {
+  width: 100%;
+}
+
+/* Body text */
+.vm-modern-text {
+  font-size: 15.5px;
+  color: var(--text-2);
+  line-height: 1.9;
+  margin-top: 22px;
+  transition: color 0.4s;
+}
+
+.vm-modern-card:hover .vm-modern-text {
+  color: rgba(242,238,234,0.75);
+}
+
+/* Footer tags */
+.vm-card-footer {
+  display: flex;
+  gap: 10px;
+  margin-top: 36px;
+  flex-wrap: wrap;
+}
+
+.vm-card-tag {
+  font-size: 10px;
+  letter-spacing: 2.5px;
+  text-transform: uppercase;
+  font-family: var(--f-body);
+  font-weight: 600;
+  color: rgba(212,175,55,0.45);
+  border: 1px solid rgba(212,175,55,0.15);
+  padding: 5px 13px;
+  border-radius: 100px;
+  transition: color 0.35s, border-color 0.35s, background 0.35s;
+}
+
+.vm-modern-card:hover .vm-card-tag {
+  color: var(--gold);
+  border-color: rgba(212,175,55,0.35);
+  background: rgba(212,175,55,0.06);
+}
+
+/* Glow bloom */
+.vm-card-glow {
+  position: absolute;
+  top: -60px;
+  right: -60px;
+  width: 240px;
+  height: 240px;
+  border-radius: 50%;
+  background: radial-gradient(circle, rgba(212,175,55,0.09) 0%, transparent 70%);
+  opacity: 0;
+  pointer-events: none;
+  transition: opacity 0.6s, transform 0.6s var(--ease);
+  transform: scale(0.7);
+}
+
+.vm-modern-card:hover .vm-card-glow {
+  opacity: 1;
+  transform: scale(1);
+}
+
+/* Shine sweep on hover */
+.vm-card-shine {
+  position: absolute;
+  inset: 0;
+  background: linear-gradient(
+    115deg,
+    transparent 30%,
+    rgba(212,175,55,0.04) 50%,
+    transparent 70%
+  );
+  transform: translateX(-100%);
+  pointer-events: none;
+  transition: none;
+}
+
+.vm-modern-card:hover .vm-card-shine {
+  transform: translateX(100%);
+  transition: transform 0.75s ease;
+}
+
+/* ── Responsive ── */
+@media (max-width: 768px) {
+  .history-grid {
+    grid-template-columns: 1fr;
+    gap: 22px;
+  }
+  .vm-modern-card {
+    padding: 38px 30px 34px;
+  }
+}
