/* ============================================================
   About Page — ULTRA PREMIUM  (About-enhanced.css)
   Cinematic · Liquid Blend · Gold Luxury Dark
   ============================================================ */

@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;0,900;1,400;1,600&family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600&display=swap');

/* ── Variables ───────────────────────────────────────────── */
:root {
  --ink: #04040c;
  --ink-2: #070712;
  --ink-3: #0a0a18;
  --ink-4: #0d0d1e;
  --card-bg: rgba(12, 12, 24, 0.92);
  --text-1: #f2eeea;
  --text-2: rgba(242, 238, 234, 0.58);
  --text-3: rgba(242, 238, 234, 0.34);
  --gold: #d4af37;
  --gold-light: #f5e27a;
  --gold-deep: #b8860b;
  --gold-dim: rgba(212, 175, 55, 0.38);
  --gold-glow: rgba(212, 175, 55, 0.18);
  --gold-faint: rgba(212, 175, 55, 0.06);
  --gold-grad: linear-gradient(135deg, #b8860b 0%, #d4af37 38%, #f5e27a 65%, #d4af37 100%);
  --border: rgba(255, 255, 255, 0.05);
  --border-g: rgba(212, 175, 55, 0.18);
  --f-display: 'Playfair Display', 'Cormorant Garamond', Georgia, serif;
  --f-body: 'DM Sans', Georgia, sans-serif;
  --f-serif: 'Cormorant Garamond', Georgia, serif;
  --ease: cubic-bezier(0.22, 1, 0.36, 1);
  --r-xl: 24px;
  --r-lg: 14px;
}

.about-modern-section {
  perspective: 2000px;
  transform-style: preserve-3d;
  overflow-x: hidden;
}

/* All cinematic sections */
.about-hero,
.about-banner,
.history-modern,
.grow-modern,
.founder-parallax-wrapper,
.timeline-parallax-wrapper {
  transform-style: preserve-3d;
  will-change: transform, opacity, filter;
}

/* ===== SPLIT BANNER STRUCTURE ===== */

.about-banner {
  position: relative;
  z-index: 10;
  overflow: hidden;
}

.history-modern {
  position: relative;
  z-index: 5;
  transform: scale(1.15);
  opacity: 0;
}

.about-banner-split {
  position: absolute;
  top: 0;
  width: 50%;
  height: 100%;
  overflow: hidden;
  z-index: 1;
}

.about-banner-left {
  left: 0;
}

.about-banner-right {
  right: 0;
}

.about-banner-split img {
  width: 200%;
  height: 100%;
  object-fit: cover;
}

.about-banner-left img {
  object-position: left center;
}

.about-banner-right img {
  object-position: right center;
}

/* Next section initially hidden & scaled */
.history-modern {
  transform: scale(0.85);
  opacity: 0;
}

/* ── Reset ───────────────────────────────────────────────── */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
}

/* ══════════════════════════════════════════════════════════
   ROOT WRAPPER
   overflow-y: visible so parallax scale transforms aren't clipped
══════════════════════════════════════════════════════════ */
.about-modern-section {
  background: var(--ink);
  color: var(--text-1);
  font-family: var(--f-body);
  overflow-x: hidden;
  overflow-y: visible;
}

/* Sections needing own clip */
.about-hero,
.about-banner {
  overflow: hidden;
}

.container {
  max-width: 1;
  margin: 0 auto;
  padding: 0 5%;
}

/* ── Shared section header ───────────────────────────────── */
.section-header {
  text-align: center;
  margin-bottom: 74px;
}

.section-eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 13px;
  color: var(--gold);
  text-transform: uppercase;
  letter-spacing: 5.5px;
  font-size: 10.5px;
  font-weight: 600;
  font-family: var(--f-body);
  margin-bottom: 22px;
}

.section-eyebrow::before,
.section-eyebrow::after {
  content: '';
  display: block;
  width: 28px;
  height: 1px;
  background: var(--gold-dim);
}

.section-title {
  font-size: clamp(2.5rem, 4.5vw, 3.9rem);
  font-family: var(--f-display);
  font-weight: 700;
  line-height: 1.1;
  color: #fff;
}

/* ══════════════════════════════════════════════════════════
   LIQUID BLEND TRANSITION OVERLAYS
   Each section has ::before / ::after pseudo-elements that
   create morphing gradient masks for silky transitions
══════════════════════════════════════════════════════════ */

/* Top blend — dark gradient fades IN from above */
.blend-top::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 280px;
  background: linear-gradient(to bottom,
      var(--ink) 0%,
      rgba(4, 4, 12, 0.85) 40%,
      transparent 100%);
  z-index: 4;
  pointer-events: none;
}

/* Bottom blend — dark gradient fades OUT to below */
.blend-bottom::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 320px;
  background: linear-gradient(to top,
      var(--ink) 0%,
      rgba(4, 4, 12, 0.9) 35%,
      transparent 100%);
  z-index: 4;
  pointer-events: none;
}

/* Gold shimmer bleed at section join */
.blend-gold::after {
  content: '';
  position: absolute;
  bottom: -1px;
  left: 0;
  right: 0;
  height: 2px;
  background: linear-gradient(to right,
      transparent 0%,
      var(--gold-dim) 20%,
      var(--gold) 50%,
      var(--gold-dim) 80%,
      transparent 100%);
  z-index: 5;
  pointer-events: none;
  animation: shimmerLine 4s ease-in-out infinite;
}

@keyframes shimmerLine {

  0%,
  100% {
    opacity: 0.4;
    transform: scaleX(0.6);
  }

  50% {
    opacity: 1.0;
    transform: scaleX(1.0);
  }
}

/* ══════════════════════════════════════════════════════════
   HERO
══════════════════════════════════════════════════════════ */
.about-hero {
  position: relative;
  height: 100vh;
  min-height: 660px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.about-hero-bg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 130%;
  object-fit: cover;
  filter: brightness(0.24) saturate(1.4) contrast(1.05);
  z-index: 1;
  will-change: transform;
}

/* Layered cinematic overlays */
.about-hero-overlay {
  position: absolute;
  inset: 0;
  z-index: 2;
  background:
    linear-gradient(to bottom, rgba(4, 4, 12, 0.08) 0%, rgba(4, 4, 12, 0.5) 60%, rgba(4, 4, 12, 1) 100%),
    radial-gradient(ellipse 75% 55% at 50% 40%, transparent 18%, rgba(4, 4, 12, 0.55) 100%);
}

/* Animated hero grain texture */
.about-hero::before {
  content: '';
  position: absolute;
  inset: 0;
  z-index: 3;
  opacity: 0.03;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='1'/%3E%3C/svg%3E");
  background-size: 200px 200px;
  pointer-events: none;
  animation: grainAnim 0.12s steps(1) infinite;
}

@keyframes grainAnim {

  0%,
  100% {
    transform: translate(0, 0);
  }

  10% {
    transform: translate(-2%, -3%);
  }

  20% {
    transform: translate(3%, 2%);
  }

  30% {
    transform: translate(-1%, 4%);
  }

  40% {
    transform: translate(4%, -1%);
  }

  50% {
    transform: translate(-3%, 1%);
  }

  60% {
    transform: translate(2%, 3%);
  }

  70% {
    transform: translate(-4%, -2%);
  }

  80% {
    transform: translate(1%, -4%);
  }

  90% {
    transform: translate(3%, -3%);
  }
}

/* Corner brackets */
.about-hero-corner {
  position: absolute;
  width: 60px;
  height: 60px;
  z-index: 5;
}

.about-hero-corner--tl {
  top: 44px;
  left: 48px;
  border-top: 1px solid var(--gold-dim);
  border-left: 1px solid var(--gold-dim);
}

.about-hero-corner--br {
  bottom: 44px;
  right: 48px;
  border-bottom: 1px solid var(--gold-dim);
  border-right: 1px solid var(--gold-dim);
}

/* Second set of inner corners */
.about-hero-corner--tl::before {
  content: '';
  position: absolute;
  top: 8px;
  left: 8px;
  width: 16px;
  height: 16px;
  border-top: 1px solid rgba(212, 175, 55, 0.2);
  border-left: 1px solid rgba(212, 175, 55, 0.2);
}

.about-hero-corner--br::before {
  content: '';
  position: absolute;
  bottom: 8px;
  right: 8px;
  width: 16px;
  height: 16px;
  border-bottom: 1px solid rgba(212, 175, 55, 0.2);
  border-right: 1px solid rgba(212, 175, 55, 0.2);
}

.about-hero-content {
  position: relative;
  z-index: 4;
  text-align: center;
  max-width: 900px;
  padding: 0 5%;
}

.about-hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 11px;
  color: var(--gold);
  text-transform: uppercase;
  letter-spacing: 7px;
  font-size: 10.5px;
  font-weight: 600;
  margin-bottom: 30px;
  font-family: var(--f-body);
}

.about-hero-badge::before,
.about-hero-badge::after {
  content: '';
  display: block;
  width: 24px;
  height: 1px;
  background: var(--gold-dim);
}

.about-hero-title {
  font-size: clamp(3.2rem, 7vw, 6.8rem);
  text-transform: uppercase;
  line-height: 1.03;
  margin-bottom: 28px;
  font-family: var(--f-display);
  font-weight: 900;
  letter-spacing: 3px;
  background: linear-gradient(165deg, #ffffff 20%, rgba(255, 255, 255, 0.42) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.about-hero-sub {
  font-size: 1.08rem;
  color: var(--text-2);
  letter-spacing: 2px;
  max-width: 440px;
  margin: 0 auto 42px;
  font-family: var(--f-serif);
  font-style: italic;
  line-height: 1.78;
}

.about-hero-ornament {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 18px;
}

.about-orn-line {
  display: block;
  width: 72px;
  height: 1px;
  background: linear-gradient(to right, transparent, var(--gold-dim));
}

.about-orn-line--r {
  background: linear-gradient(to left, transparent, var(--gold-dim));
}

.about-orn-diamond {
  color: var(--gold);
  font-size: 8px;
  text-shadow: 0 0 14px var(--gold);
  animation: diamondPulse 3s ease-in-out infinite;
}

@keyframes diamondPulse {

  0%,
  100% {
    text-shadow: 0 0 14px var(--gold), 0 0 28px transparent;
  }

  50% {
    text-shadow: 0 0 14px var(--gold), 0 0 28px var(--gold-glow);
  }
}

/* Scroll hint */
.hero-scroll-hint {
  position: absolute;
  bottom: 46px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 5;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.hero-scroll-hint::before {
  content: 'scroll';
  font-size: 9px;
  letter-spacing: 4.5px;
  text-transform: uppercase;
  color: var(--gold-dim);
  font-family: var(--f-body);
}

.hero-scroll-hint span {
  display: block;
  width: 1px;
  height: 58px;
  background: linear-gradient(to bottom, var(--gold), transparent);
  animation: scrollPulse 2.2s ease-in-out infinite;
}

@keyframes scrollPulse {
  0% {
    transform: scaleY(0);
    transform-origin: top;
    opacity: 0;
  }

  50% {
    transform: scaleY(1);
    transform-origin: top;
    opacity: 1;
  }

  100% {
    transform: scaleY(1);
    transform-origin: bottom;
    opacity: 0;
  }
}

/* ══════════════════════════════════════════════════════════
   BANNER
══════════════════════════════════════════════════════════ */
.about-banner {
  position: relative;
  height: 58vh;
  min-height: 390px;
  display: flex;
  align-items: center;
}

.about-banner-bg-wrap {
  position: absolute;
  inset: 0;
  z-index: 1;
}

.about-banner-bg {
  width: 100%;
  height: 130%;
  object-fit: cover;
  filter: brightness(0.2) saturate(1.5) contrast(1.05);
  will-change: transform;
  display: block;
}

.about-banner-overlay {
  position: absolute;
  inset: 0;
  background:
    linear-gradient(120deg, rgba(4, 4, 12, 0.86) 0%, rgba(212, 175, 55, 0.05) 48%, rgba(4, 4, 12, 0.9) 100%),
    linear-gradient(to bottom, rgba(4, 4, 12, 0.4) 0%, transparent 40%, rgba(4, 4, 12, 0.6) 100%);
}

.about-banner-content {
  position: relative;
  z-index: 2;
  text-align: center;
  width: 100%;
}

.about-banner-title {
  font-size: clamp(2.9rem, 5.5vw, 5.2rem);
  font-family: var(--f-display);
  font-weight: 700;
  text-transform: uppercase;
  line-height: 1.06;
  margin-bottom: 22px;
  color: #fff;
  letter-spacing: 3px;
}

.about-banner-desc {
  font-size: 1rem;
  color: var(--text-2);
  max-width: 560px;
  margin: 0 auto 30px;
  line-height: 1.88;
  font-family: var(--f-serif);
}

.banner-divider {
  width: 54px;
  height: 2px;
  background: var(--gold-grad);
  border-radius: 2px;
  margin: 0 auto;
  box-shadow: 0 0 18px rgba(212, 175, 55, 0.55);
