}

@keyframes dividerGlow {
  from {
    box-shadow: 0 0 10px rgba(212, 175, 55, 0.35);
    width: 54px;
  }

  to {
    box-shadow: 0 0 28px rgba(212, 175, 55, 0.7);
    width: 80px;
  }
}

/* ══════════════════════════════════════════════════════════
   VISION & MISSION
══════════════════════════════════════════════════════════ */
.history-modern {
  padding: 136px 0;
  background: var(--ink-3);
  position: relative;
  z-index: 5;
}

.history-modern::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 55% 60% at 12% 25%, rgba(212, 175, 55, 0.045) 0%, transparent 60%),
    radial-gradient(ellipse 55% 60% at 88% 75%, rgba(212, 175, 55, 0.035) 0%, transparent 60%);
}

.history-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 36px;
}

.vm-modern-card {
  padding: 58px 52px;
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--r-xl);
  position: relative;
  overflow: hidden;
  backdrop-filter: blur(20px);
  transition: transform 0.6s var(--ease), border-color 0.45s, box-shadow 0.45s;
  box-shadow: 0 14px 44px rgba(0, 0, 0, 0.45);
}

/* Animated mesh top border */
.vm-modern-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 2px;
  background: var(--gold-grad);
  opacity: 0;
  transform: scaleX(0.4);
  transform-origin: left;
  transition: opacity 0.5s, transform 0.6s var(--ease);
}

/* Glow bloom */
.vm-modern-card::after {
  content: '';
  position: absolute;
  top: -80px;
  right: -80px;
  width: 260px;
  height: 260px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(212, 175, 55, 0.07) 0%, transparent 70%);
  opacity: 0;
  transition: opacity 0.6s;
  pointer-events: none;
}

.vm-modern-card:hover {
  border-color: var(--border-g);
  transform: translateY(-14px);
  box-shadow: 0 32px 64px rgba(0, 0, 0, 0.6), 0 0 0 1px rgba(212, 175, 55, 0.18);
}

.vm-modern-card:hover::before {
  opacity: 1;
  transform: scaleX(1);
}

.vm-modern-card:hover::after {
  opacity: 1;
}

.vm-modern-badge {
  font-size: 116px;
  position: absolute;
  top: -24px;
  right: 20px;
  font-weight: 900;
  color: rgba(212, 175, 55, 0.04);
  font-family: var(--f-display);
  pointer-events: none;
  line-height: 1;
  transition: color 0.6s, transform 0.6s var(--ease);
}

.vm-modern-card:hover .vm-modern-badge {
  color: rgba(212, 175, 55, 0.1);
  transform: translateY(-8px) scale(1.04);
}

.vm-modern-title {
  font-size: 2rem;
  color: #fff;
  margin-bottom: 30px;
  font-family: var(--f-display);
  font-weight: 700;
  position: relative;
  display: inline-block;
}

.vm-modern-title::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -12px;
  width: 32px;
  height: 2px;
  background: var(--gold-grad);
  border-radius: 2px;
  transition: width 0.5s var(--ease);
  box-shadow: 0 0 10px rgba(212, 175, 55, 0.4);
}

.vm-modern-card:hover .vm-modern-title::after {
  width: 100%;
}

.vm-modern-text {
  font-size: 16px;
  color: var(--text-2);
  line-height: 1.92;
}

/* ══════════════════════════════════════════════════════════
   GROW FASTER
   z-index 6 · transform-origin for scale recession
══════════════════════════════════════════════════════════ */
.grow-modern {
  padding: 136px 0;
  background: var(--ink-2);
  border-top: 1px solid var(--border);
  position: relative;
  z-index: 6;
  transform-origin: 50% 28%;
  will-change: transform, opacity, filter;
}

/* Animated ambient mesh */
.grow-modern::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 40% 50% at 5% 50%, rgba(212, 175, 55, 0.04) 0%, transparent 60%),
    radial-gradient(ellipse 60% 40% at 95% 50%, rgba(212, 175, 55, 0.03) 0%, transparent 60%);
  animation: meshFloat 8s ease-in-out infinite alternate;
}

@keyframes meshFloat {
  from {
    opacity: 0.6;
    transform: scale(1);
  }

  to {
    opacity: 1;
    transform: scale(1.04);
  }
}

.grow-grid {
  display: grid;
  grid-template-columns: 1.05fr 0.95fr;
  gap: 92px;
  align-items: center;
}

.grow-images {
  position: relative;
  height: 634px;
  border-radius: var(--r-xl);
  overflow: hidden;
  box-shadow: 0 36px 80px rgba(0, 0, 0, 0.55);
}

/* Animated border glow ring */
.grow-images::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: var(--r-xl);
  border: 1px solid transparent;
  background: linear-gradient(var(--ink-2), var(--ink-2)) padding-box,
    var(--gold-grad) border-box;
  opacity: 0;
  transition: opacity 0.6s;
  z-index: 3;
  pointer-events: none;
}

.grow-images:hover::before {
  opacity: 0.6;
}

.grow-main-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  will-change: transform, filter;
}

.grow-stats {
  position: absolute;
  bottom: 0;
  left: 0;
  background: rgba(4, 4, 12, 0.97);
  padding: 38px 44px;
  border-radius: 0 var(--r-xl) 0 0;
  border-top: 1px solid var(--border-g);
  border-right: 1px solid var(--border-g);
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 30px;
  backdrop-filter: blur(24px);
  z-index: 2;
}

.stat-box h4 {
  font-size: 38px;
  color: var(--gold);
  margin: 0 0 8px;
  font-family: var(--f-display);
  font-weight: 700;
  text-shadow: 0 0 24px rgba(212, 175, 55, 0.38);
}

.stat-box p {
  font-size: 10.5px;
  text-transform: uppercase;
  letter-spacing: 3px;
  color: var(--text-3);
  margin: 0;
}

.grow-content {
  position: relative;
}

.grow-content-inner {
  display: flex;
  flex-direction: column;
}

.grow-content h2 {
  font-size: clamp(2.5rem, 4vw, 3.6rem);
  margin: 0 0 24px;
  font-family: var(--f-display);
  font-weight: 700;
  line-height: 1.09;
  color: #fff;
}

.grow-desc {
  color: var(--text-2);
  line-height: 1.88;
  font-size: 16px;
}

.grow-features {
  display: flex;
  flex-direction: column;
  gap: 16px;
  margin-top: 50px;
}

.feat-row {
  display: flex;
  gap: 22px;
  padding: 20px 22px;
  border-radius: var(--r-lg);
  border: 1px solid transparent;
  transition: all 0.45s var(--ease);
  align-items: flex-start;
  cursor: default;
  position: relative;
  overflow: hidden;
}

/* Feat row shimmer on hover */
.feat-row::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, rgba(212, 175, 55, 0.04), transparent);
  transform: translateX(-100%);
  transition: transform 0.7s ease;
  pointer-events: none;
}

.feat-row:hover::before {
  transform: translateX(100%);
}

.feat-row:hover {
  background: rgba(212, 175, 55, 0.035);
  border-color: var(--border-g);
  transform: translateX(9px);
}

.feat-icon {
  width: 58px;
  height: 58px;
  min-width: 58px;
  background: var(--gold-faint);
  border: 1px solid rgba(212, 175, 55, 0.2);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 21px;
  flex-shrink: 0;
  transition: all 0.45s var(--ease);
}

.feat-row:hover .feat-icon {
  background: rgba(212, 175, 55, 0.12);
  border-color: var(--gold);
  box-shadow: 0 0 24px rgba(212, 175, 55, 0.22);
  transform: scale(1.1) rotate(8deg);
}

.feat-text h4 {
  color: #fff;
  font-size: 17px;
  margin: 0 0 6px;
  font-family: var(--f-display);
  font-weight: 600;
}

.feat-text p {
  color: var(--text-2);
  line-height: 1.66;
  margin: 0;
  font-size: 14.5px;
}

/* ══════════════════════════════════════════════════════════
   PARALLAX WRAPPERS — stacking context for section transitions
══════════════════════════════════════════════════════════ */
.founder-parallax-wrapper {
  position: relative;
  z-index: 7;
  transform-origin: 50% 32%;
  will-change: transform, opacity, filter;
}

.timeline-parallax-wrapper {
  position: relative;
  z-index: 8;
  will-change: transform, opacity;
}

.tl-canvas-parallax {
  will-change: transform;
}

/* ══════════════════════════════════════════════════════════
   FOUNDER
══════════════════════════════════════════════════════════ */
.story-modern {
  padding: 136px 0 170px;
  background: var(--ink-3);
  border-top: 1px solid var(--border);
  position: relative;
  overflow: visible;
}

/* Ambient bg */
.story-modern::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 60% 55% at 0% 40%, rgba(212, 175, 55, 0.05) 0%, transparent 55%),
    radial-gradient(ellipse 50% 50% at 100% 60%, rgba(212, 175, 55, 0.04) 0%, transparent 55%);
  animation: founderMesh 9s ease-in-out infinite alternate;
}

@keyframes founderMesh {
  from {
    opacity: 0.5;
  }

  to {
    opacity: 1;
  }
}

/* Blend bridge so timeline slides up over it seamlessly */
.story-modern::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  right: 0;
  height: 260px;
  background: linear-gradient(to bottom, transparent 0%, var(--ink) 100%);
  pointer-events: none;
  z-index: 2;
}

.founder-intro-grid {
  display: grid;
  grid-template-columns: 0.82fr 1.18fr;
  gap: 92px;
  align-items: flex-start;
}

.founder-image {
  position: relative;
  overflow: visible;
}

.founder-glow {
  position: absolute;
  inset: -50px;
  background: radial-gradient(circle at center, rgba(212, 175, 55, 0.2) 0%, transparent 68%);
  z-index: 1;
  filter: blur(28px);
  pointer-events: none;
  animation: founderGlow 5s ease-in-out infinite alternate;
}

@keyframes founderGlow {
  from {
    opacity: 0.55;
    transform: scale(0.9);
  }

  to {
    opacity: 1.0;
    transform: scale(1.1);
  }
}

.founder-image-inner {
  position: relative;
  border-radius: var(--r-xl);
  overflow: hidden;
  z-index: 2;
  box-shadow: 0 36px 80px rgba(0, 0, 0, 0.65), 0 0 0 1px var(--border-g);
  will-change: transform;
}

/* Animated frame lines */
.founder-image-inner::before {
  content: '';
  position: absolute;
  top: 14px;
  right: 14px;
  bottom: 14px;
  left: 14px;
  border: 1px solid rgba(212, 175, 55, 0.12);
  border-radius: 12px;
  z-index: 3;
  pointer-events: none;
  transition: border-color 0.5s, inset 0.5s var(--ease);
}

.founder-image-inner:hover::before {
  inset: 8px;
  border-color: rgba(212, 175, 55, 0.28);
}

.founder-image-inner img {
  width: 100%;
  display: block;
  aspect-ratio: 4/5;
  object-fit: cover;
  filter: grayscale(28%) contrast(1.1) brightness(1.02);
  transition: transform 0.9s var(--ease), filter 0.9s ease;
}

.founder-image-inner:hover img {
  transform: scale(1.05);
  filter: grayscale(0%) contrast(1.1) brightness(1.04);
}

/* Founder quote */
.founder-quote {
  font-size: clamp(1.08rem, 1.75vw, 1.3rem);
  font-family: var(--f-serif);
  font-style: italic;
  font-weight: 300;
  color: var(--text-2);
  border-left: 2px solid var(--gold);
  padding-left: 30px;
  margin: 0 0 46px;
  line-height: 1.92;
  position: relative;
  will-change: transform;
}

.founder-quote::before {
  content: '"';
  position: absolute;
  top: -22px;
  left: 16px;
  font-size: 86px;
  color: rgba(212, 175, 55, 0.07);
  font-family: var(--f-display);
  line-height: 1;
  pointer-events: none;
}

.founder-quote em {
  color: var(--gold);
  font-style: normal;
  font-weight: 400;
}

/* Story cards */
.story-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 26px;
}

.story-card {
  padding: 42px 38px;
  background: var(--card-bg);
  border-radius: var(--r-xl);
  border: 1px solid var(--border);
  position: relative;
  overflow: hidden;
  transition: all 0.6s var(--ease);
  box-shadow: 0 14px 40px rgba(0, 0, 0, 0.42);
  will-change: transform;
}

/* Animated left accent bar */
.story-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 2px;
  height: 100%;
  background: var(--gold-grad);
  opacity: 0.5;
  transition: width 0.6s var(--ease), opacity 0.6s;
}

/* Hover glow corner */
.story-card::after {
  content: '';
  position: absolute;
  bottom: -40px;
  right: -40px;
  width: 140px;
  height: 140px;
  background: radial-gradient(circle, rgba(212, 175, 55, 0.07) 0%, transparent 70%);
  border-radius: 50%;
  opacity: 0;
  transition: opacity 0.5s, transform 0.5s var(--ease);
  transform: scale(0.7);
}

.story-card:hover {
  transform: translateY(-7px);
  box-shadow: 0 28px 60px rgba(0, 0, 0, 0.58), 0 0 0 1px var(--border-g);
  border-color: var(--border-g);
}

.story-card:hover::before {
  width: 100%;
  opacity: 0.03;
}

.story-card:hover::after {
  opacity: 1;
  transform: scale(1);
}

.story-card>* {
  position: relative;
  z-index: 1;
}

.story-card h3 {
  color: var(--gold);
  font-size: 21px;
  margin: 0 0 18px;
  font-family: var(--f-display);
  font-weight: 600;
}

.story-card p {
  color: var(--text-2);
  margin: 0 0 13px;
  line-height: 1.84;
  font-size: 14.5px;
}

.story-card p:last-child {
  margin: 0;
}

/* ══════════════════════════════════════════════════════════
   RESPONSIVE
══════════════════════════════════════════════════════════ */
@media (max-width: 1100px) {
  .grow-grid {
    grid-template-columns: 1fr;
    gap: 58px;
  }

  .founder-intro-grid {
    grid-template-columns: 1fr;
    gap: 58px;
  }

  .founder-image {
    max-width: 450px;
  }
}

@media (max-width: 768px) {

  .history-grid,
  .story-grid {
    grid-template-columns: 1fr;
    gap: 22px;
  }

  .grow-images {
    height: 420px;
  }

  .grow-stats {
    position: static;
    border-radius: 0 0 var(--r-xl) var(--r-xl);
    border: none;
    border-top: 1px solid var(--border);
  }

  .about-banner {
    height: auto;
    min-height: 340px;
    padding: 96px 0;
  }

  .vm-modern-card,
  .story-card {
    padding: 36px 28px;
  }

  .history-modern,
  .grow-modern,
  .story-modern {
    padding: 94px 0;
  }

  .about-hero-corner {
    width: 40px;
    height: 40px;
  }
}

@media (max-width: 480px) {
  .about-hero {
    height: 90vh;
  }

  .section-header {
    margin-bottom: 54px;
  }

  .grow-stats {
    padding: 26px 26px;
  }

  .stat-box h4 {
    font-size: 30px;
  }
}
